// src/pages/RegisterManageSub2Page.js
import React, { useEffect, useState, useCallback } from 'react'; // Added useCallback
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx'; // Import thư viện xlsx để xuất Excel
import '../Dashboard.css'; // Import CSS chung cho Dashboard
import './RegisterManageSub2Page.css'; // Import file CSS riêng cho trang này

/**
 * Component FarmListPage hiển thị danh sách các cơ sở nuôi,
 * cho phép tìm kiếm, lọc, ẩn/hiện cột và phân trang.
 */
function FarmListPage() {
  // State để lưu trữ danh sách các cơ sở được tải về từ API
  const [farms, setFarms] = useState([]);
  // State cho bộ lọc tìm kiếm chung (theo tên, địa chỉ, người đại diện, v.v.)
  const [filter, setFilter] = useState('');
  // State cho bộ lọc Tỉnh (Thành phố)
  const [selectedProvince, setSelectedProvince] = useState('');
  // State cho bộ lọc Xã (Phường)
  const [selectedCommune, setSelectedCommune] = useState('');
  // State cho bộ lọc Loài (giữ lại vì có thể có trường species lồng nhau)
  const [selectedSpecies, setSelectedSpecies] = useState('');
  // State cho bộ lọc Loại cơ sở đăng ký (Cơ sở gây nuôi / Cơ sở kinh doanh, chế biến gỗ)
  const [selectedLoaiCoSoDangKy, setSelectedLoaiCoSoDangKy] = useState('');
  // State cho bộ lọc Ngành nghề kinh doanh gỗ
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  // State cho bộ lọc Mục đích nuôi
  const [selectedMucDichNuoi, setSelectedMucDichNuoi] = useState('');
  // State cho bộ lọc Hình thức nuôi
  const [selectedHinhThucNuoi, setSelectedHinhThucNuoi] = useState('');
  // State cho bộ lọc Trạng thái
  const [selectedTrangThai, setSelectedTrangThai] = useState('');

  // State để quản lý trạng thái tải dữ liệu
  const [loading, setLoading] = useState(true);
  // State để lưu trữ thông báo lỗi
  const [error, setError] = useState(null);

  // State cho phân trang
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(10); // Mặc định 10 bản ghi mỗi trang

  // State cho việc ẩn/hiện cột
  const [columnVisibility, setColumnVisibility] = useState({
    tenCoSo: true,
    diaChiCoSo: true,
    tinhThanhPho: true,
    xaPhuong: true,
    tenNguoiDaiDien: true,
    soDienThoaiNguoiDaiDien: true,
    loaiCoSoDangKy: true,
    mucDichNuoi: true,
    hinhThucNuoi: true,
    maSoCoSoGayNuoi: true,
    tongDan: true,
    loaiHinhKinhDoanhGo: true,
    nganhNgheKinhDoanhGo: true,
    khoiLuong: true,
    ngayThanhLap: true,
    giayPhepKinhDoanh: true,
    issueDate: true,
    expiryDate: true,
    trangThai: true,
    ghiChu: true,
    vido: true,
    kinhdo: true,
    namSinh: true,
    soCCCD: true,
    ngayCapCCCD: true,
    noiCapCCCD: true,
    emailNguoiDaiDien: true,
    diaChiNguoiDaiDien: true,
    tenLamSan: true,
    tenKhoaHoc: true,
  });

  const navigate = useNavigate(); // Khởi tạo hook useNavigate

  // Hàm để lấy danh sách cơ sở từ API
  const fetchFarms = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        setLoading(false);
        setFarms([]);
        navigate('/login'); // Chuyển hướng đến trang đăng nhập nếu không có token
        return;
      }

      const config = {
        headers: {
          Authorization: `Bearer ${token}`,
        },
        params: {
          // Thêm các tham số lọc vào đây
          filter,
          province: selectedProvince,
          commune: selectedCommune,
          species: selectedSpecies,
          loaiCoSoDangKy: selectedLoaiCoSoDangKy,
          nganhNgheKinhDoanhGo: selectedNganhNgheKinhDoanhGo,
          mucDichNuoi: selectedMucDichNuoi,
          hinhThucNuoi: selectedHinhThucNuoi,
          trangThai: selectedTrangThai,
        },
      };
      const response = await axios.get('http://localhost:5000/api/farms', config);
      setFarms(response.data);
    } catch (err) {
      console.error('Lỗi khi tải danh sách cơ sở:', err);
      if (err.response && err.response.status === 401) {
        setError('Phiên đăng nhập đã hết hạn hoặc không hợp lệ. Vui lòng đăng nhập lại.');
        localStorage.removeItem('token');
        navigate('/login');
      } else {
        setError('Không thể tải danh sách cơ sở. Vui lòng thử lại sau.');
      }
      setFarms([]); // Đảm bảo farms là mảng rỗng khi có lỗi
    } finally {
      setLoading(false);
    }
  }, [filter, selectedProvince, selectedCommune, selectedSpecies, selectedLoaiCoSoDangKy, selectedNganhNgheKinhDoanhGo, selectedMucDichNuoi, selectedHinhThucNuoi, selectedTrangThai, navigate]);

  useEffect(() => {
    fetchFarms();
  }, [fetchFarms]);

  // Lọc dữ liệu dựa trên các tiêu chí
  const filteredFarms = farms.filter(farm => {
    const matchesFilter = filter === '' ||
      Object.values(farm).some(value =>
        String(value).toLowerCase().includes(filter.toLowerCase())
      );
    const matchesProvince = selectedProvince === '' || farm.tinhThanhPho === selectedProvince;
    const matchesCommune = selectedCommune === '' || farm.xaPhuong === selectedCommune;
    const matchesSpecies = selectedSpecies === '' || (farm.loaiDongVatRung && farm.loaiDongVatRung.some(s => s.tenLamSan === selectedSpecies));
    const matchesLoaiCoSoDangKy = selectedLoaiCoSoDangKy === '' || farm.loaiCoSoDangKy === selectedLoaiCoSoDangKy;
    const matchesNganhNgheKinhDoanhGo = selectedNganhNgheKinhDoanhGo === '' || farm.nganhNgheKinhDoanhGo === selectedNganhNgheKinhDoanhGo;
    const matchesMucDichNuoi = selectedMucDichNuoi === '' || farm.mucDichNuoi === selectedMucDichNuoi;
    const matchesHinhThucNuoi = selectedHinhThucNuoi === '' || farm.hinhThucNuoi === selectedHinhThucNuoi;
    const matchesTrangThai = selectedTrangThai === '' || farm.trangThai === selectedTrangThai;

    return matchesFilter && matchesProvince && matchesCommune && matchesSpecies &&
           matchesLoaiCoSoDangKy && matchesNganhNgheKinhDoanhGo &&
           matchesMucDichNuoi && matchesHinhThucNuoi && matchesTrangThai;
  });

  // Lấy danh sách các tỉnh/thành phố và xã/phường duy nhất để làm bộ lọc
  const uniqueProvinces = [...new Set(farms.map(farm => farm.tinhThanhPho).filter(Boolean))];
  const uniqueCommunes = [...new Set(farms.map(farm => farm.xaPhuong).filter(Boolean))];
  const uniqueSpecies = [...new Set(farms.flatMap(farm => farm.loaiDongVatRung ? farm.loaiDongVatRung.map(s => s.tenLamSan) : []).filter(Boolean))];
  const uniqueLoaiCoSoDangKy = [...new Set(farms.map(farm => farm.loaiCoSoDangKy).filter(Boolean))];
  const uniqueNganhNgheKinhDoanhGo = [...new Set(farms.map(farm => farm.nganhNgheKinhDoanhGo).filter(Boolean))];
  const uniqueMucDichNuoi = [...new Set(farms.map(farm => farm.mucDichNuoi).filter(Boolean))];
  const uniqueHinhThucNuoi = [...new Set(farms.map(farm => farm.hinhThucNuoi).filter(Boolean))];
  const uniqueTrangThai = [...new Set(farms.map(farm => farm.trangThai).filter(Boolean))];


  // Logic phân trang
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredFarms.slice(indexOfFirstItem, indexOfLastItem);
  const totalPages = Math.ceil(filteredFarms.length / itemsPerPage);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);
  const nextPage = () => setCurrentPage(prev => Math.min(prev + 1, totalPages));
  const prevPage = () => setCurrentPage(prev => Math.max(prev - 1, 1));

  // Hàm xử lý khi thay đổi hiển thị cột
  const handleColumnVisibilityChange = (e) => {
    setColumnVisibility({
      ...columnVisibility,
      [e.target.name]: e.target.checked,
    });
  };

  // Hàm xuất dữ liệu ra Excel
  const exportToExcel = () => {
    const dataToExport = filteredFarms.map(farm => {
      const row = {};
      for (const key in columnVisibility) {
        if (columnVisibility[key]) {
          // Xử lý các trường đặc biệt nếu cần
          if (key === 'loaiDongVatRung' && farm.loaiDongVatRung) {
            row['Loài động vật rừng'] = farm.loaiDongVatRung.map(s => s.tenLamSan).join(', ');
          } else {
            row[key] = farm[key];
          }
        }
      }
      return row;
    });

    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "DanhSachCoSo");
    XLSX.writeFile(wb, "danh_sach_co_so.xlsx");
  };

  // Hàm xử lý click vào một hàng để xem chi tiết
  const handleRowClick = (farmId) => {
    navigate(`/farm-detail/${farmId}`);
  };

  if (loading) return <div className="loading-message">Đang tải dữ liệu...</div>;
  if (error) return <div className="error-message">{error}</div>;

  return (
    <div className="farm-list-page-container">
      <h1 className="page-title">Quản lý Cơ sở</h1>

      <div className="filter-controls">
        <input
          type="text"
          placeholder="Tìm kiếm theo tên, địa chỉ, người đại diện..."
          value={filter}
          onChange={(e) => {
            setFilter(e.target.value);
            setCurrentPage(1); // Reset về trang 1 khi tìm kiếm
          }}
          className="search-input"
        />

        <select
          value={selectedLoaiCoSoDangKy}
          onChange={(e) => {
            setSelectedLoaiCoSoDangKy(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả loại hình đăng ký</option>
          {uniqueLoaiCoSoDangKy.map(type => (
            <option key={type} value={type}>{type}</option>
          ))}
        </select>

        <select
          value={selectedProvince}
          onChange={(e) => {
            setSelectedProvince(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả Tỉnh/Thành phố</option>
          {uniqueProvinces.map(province => (
            <option key={province} value={province}>{province}</option>
          ))}
        </select>

        <select
          value={selectedCommune}
          onChange={(e) => {
            setSelectedCommune(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả Xã/Phường</option>
          {uniqueCommunes.map(commune => (
            <option key={commune} value={commune}>{commune}</option>
          ))}
        </select>

        <select
          value={selectedTrangThai}
          onChange={(e) => {
            setSelectedTrangThai(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả Trạng thái</option>
          {uniqueTrangThai.map(status => (
            <option key={status} value={status}>{status}</option>
          ))}
        </select>

        {/* Các bộ lọc khác có thể thêm vào đây */}
        <select
          value={selectedMucDichNuoi}
          onChange={(e) => {
            setSelectedMucDichNuoi(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả Mục đích nuôi</option>
          {uniqueMucDichNuoi.map(purpose => (
            <option key={purpose} value={purpose}>{purpose}</option>
          ))}
        </select>

        <select
          value={selectedHinhThucNuoi}
          onChange={(e) => {
            setSelectedHinhThucNuoi(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả Hình thức nuôi</option>
          {uniqueHinhThucNuoi.map(form => (
            <option key={form} value={form}>{form}</option>
          ))}
        </select>

        <select
          value={selectedNganhNgheKinhDoanhGo}
          onChange={(e) => {
            setSelectedNganhNgheKinhDoanhGo(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả Ngành nghề kinh doanh gỗ</option>
          {uniqueNganhNgheKinhDoanhGo.map(trade => (
            <option key={trade} value={trade}>{trade}</option>
          ))}
        </select>

        <select
          value={selectedSpecies}
          onChange={(e) => {
            setSelectedSpecies(e.target.value);
            setCurrentPage(1);
          }}
          className="filter-select"
        >
          <option value="">Tất cả Loài</option>
          {uniqueSpecies.map(species => (
            <option key={species} value={species}>{species}</option>
          ))}
        </select>

        <button onClick={exportToExcel} className="export-button">
          Xuất Excel
        </button>
      </div>

      <div className="column-visibility-controls">
        <h3>Ẩn/Hiện cột:</h3>
        {Object.keys(columnVisibility).map(key => (
          <label key={key} className="column-checkbox-label">
            <input
              type="checkbox"
              name={key}
              checked={columnVisibility[key]}
              onChange={handleColumnVisibilityChange}
            />
            {/* Tên hiển thị của cột, bạn có thể tùy chỉnh nếu muốn */}
            {key === 'tenCoSo' && 'Tên cơ sở'}
            {key === 'diaChiCoSo' && 'Địa chỉ cơ sở'}
            {key === 'tinhThanhPho' && 'Tỉnh/Thành phố'}
            {key === 'xaPhuong' && 'Xã/Phường'}
            {key === 'tenNguoiDaiDien' && 'Tên người đại diện'}
            {key === 'soDienThoaiNguoiDaiDien' && 'SĐT người đại diện'}
            {key === 'loaiCoSoDangKy' && 'Loại hình đăng ký'}
            {key === 'mucDichNuoi' && 'Mục đích nuôi'}
            {key === 'hinhThucNuoi' && 'Hình thức nuôi'}
            {key === 'maSoCoSoGayNuoi' && 'Mã số cơ sở gây nuôi'}
            {key === 'tongDan' && 'Tổng đàn'}
            {key === 'loaiHinhKinhDoanhGo' && 'Loại hình KD gỗ'}
            {key === 'nganhNgheKinhDoanhGo' && 'Ngành nghề KD gỗ'}
            {key === 'khoiLuong' && 'Khối lượng gỗ'}
            {key === 'ngayThanhLap' && 'Ngày thành lập'}
            {key === 'giayPhepKinhDoanh' && 'Giấy phép KD'}
            {key === 'issueDate' && 'Ngày cấp GP'}
            {key === 'expiryDate' && 'Ngày hết hạn GP'}
            {key === 'trangThai' && 'Trạng thái'}
            {key === 'ghiChu' && 'Ghi chú'}
            {key === 'vido' && 'Vĩ độ'}
            {key === 'kinhdo' && 'Kinh độ'}
            {key === 'namSinh' && 'Năm sinh'}
            {key === 'soCCCD' && 'Số CCCD'}
            {key === 'ngayCapCCCD' && 'Ngày cấp CCCD'}
            {key === 'noiCapCCCD' && 'Nơi cấp CCCD'}
            {key === 'emailNguoiDaiDien' && 'Email người đại diện'}
            {key === 'diaChiNguoiDaiDien' && 'Địa chỉ người đại diện'}
            {key === 'tenLamSan' && 'Tên lâm sản'}
            {key === 'tenKhoaHoc' && 'Tên khoa học'}
          </label>
        ))}
      </div>

      {filteredFarms.length === 0 ? (
        <p className="no-data-message">Không tìm thấy cơ sở nào phù hợp với tiêu chí tìm kiếm/lọc.</p>
      ) : (
        <div className="table-responsive">
          <table className="farm-table">
            <thead>
              <tr>
                {columnVisibility.tenCoSo && <th>Tên cơ sở</th>}
                {columnVisibility.diaChiCoSo && <th>Địa chỉ cơ sở</th>}
                {columnVisibility.tinhThanhPho && <th>Tỉnh/Thành phố</th>}
                {columnVisibility.xaPhuong && <th>Xã/Phường</th>}
                {columnVisibility.tenNguoiDaiDien && <th>Tên người đại diện</th>}
                {columnVisibility.soDienThoaiNguoiDaiDien && <th>Số điện thoại</th>}
                {columnVisibility.loaiCoSoDangKy && <th>Loại hình đăng ký</th>}
                {columnVisibility.mucDichNuoi && <th>Mục đích nuôi</th>}
                {columnVisibility.hinhThucNuoi && <th>Hình thức nuôi</th>}
                {columnVisibility.maSoCoSoGayNuoi && <th>Mã số CSGN</th>}
                {columnVisibility.tongDan && <th>Tổng đàn</th>}
                {columnVisibility.loaiHinhKinhDoanhGo && <th>Loại hình KD gỗ</th>}
                {columnVisibility.nganhNgheKinhDoanhGo && <th>Ngành nghề KD gỗ</th>}
                {columnVisibility.khoiLuong && <th>Khối lượng</th>}
                {columnVisibility.ngayThanhLap && <th>Ngày thành lập</th>}
                {columnVisibility.giayPhepKinhDoanh && <th>Giấy phép KD</th>}
                {columnVisibility.issueDate && <th>Ngày cấp GP</th>}
                {columnVisibility.expiryDate && <th>Ngày hết hạn GP</th>}
                {columnVisibility.trangThai && <th>Trạng thái</th>}
                {columnVisibility.ghiChu && <th>Ghi chú</th>}
                {columnVisibility.vido && <th>Vĩ độ</th>}
                {columnVisibility.kinhdo && <th>Kinh độ</th>}
                {columnVisibility.namSinh && <th>Năm sinh</th>}
                {columnVisibility.soCCCD && <th>Số CCCD</th>}
                {columnVisibility.ngayCapCCCD && <th>Ngày cấp CCCD</th>}
                {columnVisibility.noiCapCCCD && <th>Nơi cấp CCCD</th>}
                {columnVisibility.emailNguoiDaiDien && <th>Email người đại diện</th>}
                {columnVisibility.diaChiNguoiDaiDien && <th>Địa chỉ người đại diện</th>}
                {columnVisibility.tenLamSan && <th>Tên lâm sản</th>}
                {columnVisibility.tenKhoaHoc && <th>Tên khoa học</th>}
              </tr>
            </thead>
            <tbody>
              {currentItems.map((farm) => (
                <tr key={farm._id} onClick={() => handleRowClick(farm._id)} className="farm-table-row-clickable">
                  {columnVisibility.tenCoSo && <td>{farm.tenCoSo}</td>}
                  {columnVisibility.diaChiCoSo && <td>{farm.diaChiCoSo}</td>}
                  {columnVisibility.tinhThanhPho && <td>{farm.tinhThanhPho}</td>}
                  {columnVisibility.xaPhuong && <td>{farm.xaPhuong}</td>}
                  {columnVisibility.tenNguoiDaiDien && <td>{farm.tenNguoiDaiDien}</td>}
                  {columnVisibility.soDienThoaiNguoiDaiDien && <td>{farm.soDienThoaiNguoiDaiDien}</td>}
                  {columnVisibility.loaiCoSoDangKy && <td>{farm.loaiCoSoDangKy || 'N/A'}</td>}
                  {columnVisibility.mucDichNuoi && <td>{farm.mucDichNuoi || 'N/A'}</td>}
                  {columnVisibility.hinhThucNuoi && <td>{farm.hinhThucNuoi || 'N/A'}</td>}
                  {columnVisibility.maSoCoSoGayNuoi && <td>{farm.maSoCoSoGayNuoi || 'N/A'}</td>}
                  {columnVisibility.tongDan && <td>{farm.tongDan || 'N/A'}</td>}
                  {columnVisibility.loaiHinhKinhDoanhGo && <td>{farm.loaiHinhKinhDoanhGo || 'N/A'}</td>}
                  {columnVisibility.nganhNgheKinhDoanhGo && <td>{farm.nganhNgheKinhDoanhGo || 'N/A'}</td>}
                  {columnVisibility.khoiLuong && <td>{farm.khoiLuong || 'N/A'}</td>}
                  {columnVisibility.ngayThanhLap && <td>{farm.ngayThanhLap ? new Date(farm.ngayThanhLap).toLocaleDateString() : 'N/A'}</td>}
                  {columnVisibility.giayPhepKinhDoanh && <td>{farm.giayPhepKinhDoanh || 'N/A'}</td>}
                  {columnVisibility.issueDate && <td>{farm.issueDate ? new Date(farm.issueDate).toLocaleDateString() : 'N/A'}</td>}
                  {columnVisibility.expiryDate && <td>{farm.expiryDate ? new Date(farm.expiryDate).toLocaleDateString() : 'N/A'}</td>}
                  {columnVisibility.trangThai && <td>{farm.trangThai || 'N/A'}</td>}
                  {columnVisibility.ghiChu && <td>{farm.ghiChu || 'N/A'}</td>}
                  {columnVisibility.vido && <td>{farm.vido || 'N/A'}</td>}
                  {columnVisibility.kinhdo && <td>{farm.kinhdo || 'N/A'}</td>}
                  {columnVisibility.namSinh && <td>{farm.namSinh || 'N/A'}</td>}
                  {columnVisibility.soCCCD && <td>{farm.soCCCD || 'N/A'}</td>}
                  {columnVisibility.ngayCapCCCD && <td>{farm.ngayCapCCCD ? new Date(farm.ngayCapCCCD).toLocaleDateString() : 'N/A'}</td>}
                  {columnVisibility.noiCapCCCD && <td>{farm.noiCapCCCD || 'N/A'}</td>}
                  {columnVisibility.emailNguoiDaiDien && <td>{farm.emailNguoiDaiDien || 'N/A'}</td>}
                  {columnVisibility.diaChiNguoiDaiDien && <td>{farm.diaChiNguoiDaiDien || 'N/A'}</td>}
                  {columnVisibility.tenLamSan && <td>{farm.loaiDongVatRung && farm.loaiDongVatRung.length > 0 ? farm.loaiDongVatRung.map(s => s.tenLamSan).join(', ') : 'N/A'}</td>}
                  {columnVisibility.tenKhoaHoc && <td>{farm.loaiDongVatRung && farm.loaiDongVatRung.length > 0 ? farm.loaiDongVatRung.map(s => s.tenKhoaHoc).join(', ') : 'N/A'}</td>}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Phân trang */}
      {totalPages > 1 && (
        <div className="pagination-container">
          <div className="pagination-info">
            {indexOfFirstItem + 1} - {Math.min(indexOfLastItem, filteredFarms.length)} / {filteredFarms.length} bản ghi
          </div>
          <div className="pagination-controls">
            <button onClick={prevPage} disabled={currentPage === 1} className="pagination-button">«</button>
            {Array.from({ length: totalPages }, (_, i) => (
              <button
                key={i + 1}
                onClick={() => paginate(i + 1)}
                className={`pagination-button ${currentPage === i + 1 ? 'active' : ''}`}
              >
                {i + 1}
              </button>
            ))}
            <button onClick={nextPage} disabled={currentPage === totalPages} className="pagination-button">»</button>
          </div>
          <div className="items-per-page">
            <select value={itemsPerPage} onChange={(e) => {
              setItemsPerPage(Number(e.target.value));
              setCurrentPage(1); // Đặt lại về trang đầu tiên khi số mục mỗi trang thay đổi
            }}>
              <option value="5">5 bản ghi/trang</option>
              <option value="10">10 bản ghi/trang</option>
              <option value="15">15 bản ghi/trang</option>
              <option value="20">20 bản ghi/trang</option>
              <option value="50">50 bản ghi/trang</option>
            </select>
          </div>
        </div>
      )}
    </div>
  );
}

export default FarmListPage;
